mapper.select:
SELECT * FROM (SELECT CO_ID, MST_CD, MST_NM, MST_MDL_NM, MST_DESC, SUB_TBL_CFG, USE_FLG, CRE_USR_ID, CRE_DT, UPD_USR_ID, UPD_DT FROM COM_MST_CD WHERE 1=1 AND CO_ID = #{coId}
AND UPPER(MST_CD) LIKE '%' || UPPER(#{mstCd}) || '%'
AND UPPER(MST_NM) ILIKE '%' || UPPER(#{mstNm}) || '%'
AND UPPER(MST_MDL_NM) = UPPER(#{mstMdlNm})
AND USE_FLG = #{useFlg}
ORDER BY ${sort.sortField} ${sort.sortType}, UPD_DT DESC
ORDER BY UPD_DT DESC
) AS MST_LIST WHERE 1=1
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

SELECT COUNT(*) FROM COM_MST_CD WHERE 1=1 AND CO_ID = #{coId}
AND UPPER(MST_CD) LIKE '%' || UPPER(#{mstCd}) || '%'
AND UPPER(MST_NM) ILIKE '%' || UPPER(#{mstNm}) || '%'
AND UPPER(MST_MDL_NM) = UPPER(#{mstMdlNm})
AND USE_FLG = #{useFlg}

SELECT CO_ID, MST_CD, MST_NM, MST_MDL_NM, MST_DESC, USE_FLG, CRE_USR_ID, CRE_DT, UPD_USR_ID, UPD_DT FROM COM_MST_CD WHERE 1=1 AND CO_ID = #{coId}
AND MST_CD = #{mstCd}
AND USE_FLG = #{useFlg}
LIMIT 1

